 40→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 41→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 42→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 43→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 44→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 45→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 46→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 47→
 48→const editorTheme = {
 49→  paragraph: 'editor-paragraph',
 50→  heading: {
 51→    h1: 'editor-heading-h1',
 52→    h2: 'editor-heading-h2',
 53→    h3: 'editor-heading-h3',
 54→  },
 55→  quote: 'editor-quote',
 56→  text: {
 57→    bold: 'editor-text-bold',
 58→    italic: 'editor-text-italic',
 59→    underline: 'editor-text-underline',
 60→  }
 61→};
 62→
 63→const editorConfig = {
 64→  namespace: "MyLexicalEditor",
 65→  theme: editorTheme,
 66→  nodes: [ImageNode, HeadingNode, QuoteNode, MentionNode],
 67→  onError(error){
 68→    throw error;
 69→  },
 70→};
 71→
 72→const AppAuthModal = () => {
 73→  const {showAuthModal, closeAuthModal} = useAuth();
 74→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 75→}
 76→
 77→const AppSplash = () => {
 78→  const { loading } = useAuth();
 79→  return <Loader isLoading={loading} />;
 80→}
 81→
 82→const HomeWithEditor = () => (
 83→  <LexicalComposer initialConfig={editorConfig}>
 84→    <HomePage/>
 85→  </LexicalComposer>
 86→);
 87→
 88→const SuspenseFallback = () => (
 89→  <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
 90→    <Loader />
 91→  </div>
 92→);
 93→
 94→const App = () => {
 95→
 96→  return (
 97→    <>
 98→      <BrowserRouter>
 99→        <SeoManager />
100→        <AppSplash />
101→        <Suspense fallback={<SuspenseFallback />}>
102→          <AppAuthModal/>
103→          <Routes>
104→            <Route path='/' element={<Navigate to='/home' replace/>}/>
105→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
106→            <Route path='/profile' element={<ProtectedRoute><MyProfile/></ProtectedRoute>}>
107→              <Route index element={<ProfilePostCards/>} />
108→              <Route path='media' element={<ProfileMediaSection/>} />
109→              <Route path='myOpinions' element={<MyOpinions/>}/>
110→              <Route path='stories' element={<ProfileStoriesSection/>}/>
111→            </Route>
112→
113→            <Route path='/visitProfile' element={<Visitprofile/>}>
114→              <Route index element={<VisitedProfilePostCards/>}/>
115→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
116→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
117→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
118→            </Route>
119→
120→            <Route path='/u/:username' element={<Visitprofile/>}>
121→              <Route index element={<VisitedProfilePostCards/>}/>
122→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
123→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
124→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
125→            </Route>
126→
127→            <Route path='/home' element={<HomeWithEditor/>}>
128→              <Route index element={<PostCards/>}/>
129→              <Route path='following' element={<PostCards/>}/>
130→              <Route path='for-you' element={<PostCards/>}/>
131→              <Route path='explore' element={<ExplorePage/>}/>
132→              <Route path='contentViewer' element={<ContentView/>}/>
133→              <Route path='post/:journalId' element={<ContentView/>}/>
134→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
135→              <Route path='bookmark' element={<Bookmarks/>}/>
136→              <Route path='opinions'element={<OpinionsPage/>}/>
137→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
138→
139→              <Route path='settings' element={<SettingsPage/>}/>
140→
141→              {/* Stories routes */}
142→              <Route path='stories' element={<StoryBrowser/>}/>
143→              <Route path='stories/library' element={<StoryLibrary/>}/>
144→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
145→              <Route path='stories/new' element={<StoryEditor/>}/>
146→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
147→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
148→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
149→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
150→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
151→
152→              {/* route for nested notifications */}
153→              <Route path='notifications' element={<Notifications/>}>
154→                <Route index element={<NotificationCards/>}/>
155→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
156→              </Route>
157→            </Route>
158→
159→            <Route path='/login' element={<LoginPage/>}/>
160→            <Route path='/signUp' element={<SignUp/>}/>
161→            <Route path='*' element={<NotFound/>}/>
162→          </Routes>
163→        </Suspense>
164→      </BrowserRouter>
165→    </>
166→  )
167→}
168→
169→export default App
