102→        if (isGuest) {
103→            return [homeLink, exploreLink,
104→                { label: 'Log in', action: () => navigate('/login'), className: 'write-journal-bttn' },
105→                { label: 'Sign up', action: () => navigate('/signUp'), className: 'sidebar-links' },
