168→    const handleOnboardingComplete = useCallback((action) => {
169→        setShowOnboarding(false);
170→        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
171→        if (action === 'write') {
172→            handleOpenTextEditor();
