198→
199→        handleOpenTextEditor({
200→            initialTitle: launchState?.initialTitle || ''
201→        });
202→
203→        navigate(location.pathname, {replace: true, state: null});
204→    }, [location.state, location.pathname, navigate, handleOpenTextEditor]);
