224→
225→    useEffect(() => {
226→        if(session && !loading && user){
227→            const profileData = user?.userData?.[0];
228→            const exists = !!profileData;
229→            const onboarded = profileData?.onboarding_completed ?? true;
230→            if(!exists || !onboarded){
