119→
120→    // Don't render anything if no confidence or no posts
121→    if (!data || data.confidence === 'none' || !data.posts?.length) {
122→        return null;
123→    }
124→
125→    const label = CONFIDENCE_LABELS[data.confidence];
126→    if (!label) return null;
127→
128→    return (
129→        <section className="rp-section">
130→            <h3 className="rp-heading">
131→                <svg className="rp-heading-icon" viewBox="0 0 16 16" fill="none">
132→                    <path d="M8 1l1.796 4.236L14.5 6.18l-3.25 3.382.588 4.938L8 12.236 4.162 14.5l.588-4.938L1.5 6.18l4.704-.944z"
